#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
int n,a[N];
void Mergesort(int l,int r){
    if(l>=r)
    	return;
    int mid=l+r>>1;
    Mergesort(l,mid);
    Mergesort(mid+1,r);
    int i=l,j=mid+1,b[N],sum=0;
    while(i<=mid && j<=r){
        if(a[i]<=a[j])
            b[++sum]=a[i++];
        else
            b[++sum]=a[j++];
    }
    while(i<=mid)
        b[++sum]=a[i++];
    while(j<=r)
        b[++sum]=a[j++];
    for(int i=l;i<=r;i++)
    	a[i]=b[i-l+1];
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    Mergesort(1,n);
    for(int i=1;i<=n;i++)
        printf("%d ",a[i]);
    printf("\n");
    return 0;
}
